/// Creates the EVM config with access to the transaction pool for block verification.
fn build_evm_with_pool(
    self,
    ctx: &BuilderContext<Node>,
    pool: impl reth_transaction_pool::TransactionPoolExt + Clone + 'static,
) -> impl Future<Output = eyre::Result<(Self::EVM, Self::Executor)>> + Send
where
    Self: Sized,
{
    // Default implementation ignores pool and calls build_evm
    self.build_evm(ctx)
}
